import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { uploadResume, analyzeResume } from '../services/resume';
import { DocumentArrowUpIcon, DocumentTextIcon, XMarkIcon } from '@heroicons/react/24/outline';

const Analyze = () => {
  const [step, setStep] = useState(1);
  const [file, setFile] = useState(null);
  const [resumeText, setResumeText] = useState('');
  const [jobDescription, setJobDescription] = useState('');
  const [loading, setLoading] = useState(false);
  const [fileName, setFileName] = useState('');
  const navigate = useNavigate();

  const handleFileUpload = async (e) => {
    const selectedFile = e.target.files[0];
    if (!selectedFile) return;

    setFile(selectedFile);
    setFileName(selectedFile.name);
    
    const formData = new FormData();
    formData.append('resume', selectedFile);

    try {
      setLoading(true);
      const response = await uploadResume(selectedFile);
      setResumeText(response.resumeText);
      setStep(2);
    } catch (error) {
      console.error('Upload failed:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleAnalyze = async () => {
    if (!resumeText || !jobDescription) {
      alert('Please provide both resume and job description');
      return;
    }

    try {
      setLoading(true);
      const result = await analyzeResume({
        resumeText,
        jobDescription,
        fileName
      });
      navigate(`/result/${result.analysisId}`);
    } catch (error) {
      console.error('Analysis failed:', error);
    } finally {
      setLoading(false);
    }
  };

  const removeFile = () => {
    setFile(null);
    setResumeText('');
    setFileName('');
  };

  return (
    <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
      <div className="mb-8">
        <h1 className="text-2xl font-bold text-gray-900">Analyze your Resume</h1>
        <p className="text-gray-600">
          Upload your resume and paste the job description to get AI-powered insights.
        </p>
      </div>

      {/* Steps */}
      <div className="mb-8">
        <div className="flex items-center">
          <div className={`flex items-center ${step >= 1 ? 'text-indigo-600' : 'text-gray-400'}`}>
            <div className={`w-8 h-8 rounded-full flex items-center justify-center border-2 
              ${step >= 1 ? 'border-indigo-600 bg-indigo-50' : 'border-gray-300'}`}>
              1
            </div>
            <span className="ml-2 font-medium">Upload Resume</span>
          </div>
          <div className={`flex-1 h-0.5 mx-4 ${step >= 2 ? 'bg-indigo-600' : 'bg-gray-300'}`} />
          <div className={`flex items-center ${step >= 2 ? 'text-indigo-600' : 'text-gray-400'}`}>
            <div className={`w-8 h-8 rounded-full flex items-center justify-center border-2 
              ${step >= 2 ? 'border-indigo-600 bg-indigo-50' : 'border-gray-300'}`}>
              2
            </div>
            <span className="ml-2 font-medium">Job Description</span>
          </div>
        </div>
      </div>

      <div className="card">
        {/* Step 1: Upload Resume */}
        {step === 1 && (
          <div className="text-center">
            {!file ? (
              <div>
                <DocumentArrowUpIcon className="h-16 w-16 text-gray-400 mx-auto mb-4" />
                <h3 className="text-lg font-medium text-gray-900 mb-2">
                  Upload your resume (PDF/DOCX)
                </h3>
                <p className="text-sm text-gray-500 mb-4">
                  Maximum file size: 5MB
                </p>
                <label className="btn-primary cursor-pointer">
                  Choose File
                  <input
                    type="file"
                    className="hidden"
                    accept=".pdf,.docx"
                    onChange={handleFileUpload}
                    disabled={loading}
                  />
                </label>
              </div>
            ) : (
              <div className="flex items-center justify-between p-4 bg-gray-50 rounded-lg">
                <div className="flex items-center">
                  <DocumentTextIcon className="h-8 w-8 text-indigo-600 mr-3" />
                  <div className="text-left">
                    <p className="font-medium text-gray-900">{fileName}</p>
                    <p className="text-sm text-gray-500">
                      {loading ? 'Processing...' : 'Ready for analysis'}
                    </p>
                  </div>
                </div>
                <button
                  onClick={removeFile}
                  className="p-1 hover:bg-gray-200 rounded-full"
                >
                  <XMarkIcon className="h-5 w-5 text-gray-500" />
                </button>
              </div>
            )}
          </div>
        )}

        {/* Step 2: Job Description */}
        {step === 2 && (
          <div>
            <h3 className="text-lg font-medium text-gray-900 mb-4">
              Paste Job Description
            </h3>
            <textarea
              rows="10"
              className="input-field"
              placeholder="Paste the job description here..."
              value={jobDescription}
              onChange={(e) => setJobDescription(e.target.value)}
            />
            
            <div className="mt-6 flex justify-end space-x-3">
              <button
                onClick={() => setStep(1)}
                className="btn-secondary"
              >
                Back
              </button>
              <button
                onClick={handleAnalyze}
                disabled={loading || !jobDescription}
                className="btn-primary"
              >
                {loading ? 'Analyzing...' : 'Analyze Now'}
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default Analyze;
